module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [15:0] quotient;
    reg [4:0] i;

    always @(*) begin
        dividend = A;
        divisor = B;
        remainder = 0;
        quotient = 0;

        for (i = 0; i < 16; i = i + 1) begin
            remainder = {remainder[14:0], dividend[15]};
            dividend = {dividend[14:0], 1'b0};

            if (remainder >= divisor) begin
                remainder = remainder - divisor;
                quotient = {quotient[14:0], 1'b1};
            end
            else begin
                quotient = {quotient[14:0], 1'b0};
            end
        end

        result = quotient;
    end

    assign odd = remainder;

endmodule
